function greedyRoute(places){if(!places.length)return[];const result=[places[0]];const rem=places.slice(1);while(rem.length){const last=result[result.length-1];let best=0,bestDist=Infinity;rem.forEach((p,i)=>{const dist=Math.hypot(p.lat-last.lat,p.lon-last.lon);if(dist<bestDist){bestDist=dist;best=i;}});result.push(rem.splice(best,1)[0]);}return result;}// 황금각(137.5°) 기반으로 겹치지 않는 hue 배열 생성
