React.useEffect(()=>{if(!open){setKbOffset(0);return;}const vv=window.visualViewport;if(!vv)return;const update=()=>{const kb=Math.max(0,window.innerHeight-vv.height-vv.offsetTop);setKbOffset(kb);};vv.addEventListener('resize',update);vv.addEventListener('scroll',update);update();return()=>{vv.removeEventListener('resize',update);vv.removeEventListener('scroll',update);};},[open]);// 도시 카드 드래그 리오더
